    padding: 8px 18px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.send-btn:hover:not(:disabled) {
    background: #005e45;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: default;
}

/* ── Thread panel ── */
.thread-panel {
    width: 25%;
    min-width: 260px;
    background: #fff;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #e8e8e8;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    color: #666;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.thread-root-quote .author {
    font-size: 0.85rem;
}

.thread-root-quote p {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #444;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
}

.thread-messages .message-bubble {
    padding: 6px 0;
}

/* ── Empty state ── */
.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #999;
    font-size: 1.1rem;
}
"}

