toolArgs.file_text:
/* ── Root layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

/* ── Sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.15);
    border-left-color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #b5a7b5;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main message area ── */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e8e8e8;
    border-right: 1px solid #e8e8e8;
    overflow: hidden;
    transition: width 0.2s;
}

.message-area.expanded {
    width: 80%;
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.message-header h4 {
    margin: 0;
    font-size: 1.05rem;
}

.header-desc {
    font-size: 0.8rem;
    color: #616061;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    font-size: 0.8rem;
    color: #888;
}

.message-row {
    position: relative;
    padding: 6px 0;
    border-radius: 6px;
    transition: background 0.1s;
}

.message-row:hover {
    background: #f8f8f8;
}

.message-bubble {
    padding: 4px 8px;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
}

.timestamp {
    font-size: 0.72rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    margin-top: 2px;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.78rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #e0e7ff;
    border-color: #93a8f5;
}

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ── Message hover actions ── */
.message-actions {
    position: absolute;
    top: 2px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
